/* ── Settings Dashboard Layout ── */

.settings-dashboard {
    display: flex;
    min-height: calc(100vh - 100px);
    gap: 0;
    background: #f8f9fa;
    border-radius: 8px;
    overflow: hidden;
    border: 1px solid #dee2e6;
}

/* ── Sidebar ── */

.settings-sidebar {
    width: 240px;
    min-width: 240px;
    background: #fff;
    border-right: 1px solid #dee2e6;
    padding: 1.5rem 0;
}

.settings-sidebar-title {
    padding: 0 1.25rem 1rem;
    margin: 0;
    font-size: 1.1rem;
    font-weight: 600;
    color: #333;
    border-bottom: 1px solid #eee;
}

.settings-nav {
    list-style: none;
    padding: 0.5rem 0;
    margin: 0;
}

.settings-nav-item {
    display: flex;
    align-items: center;
    gap: 0.75rem;
    padding: 0.75rem 1.25rem;
    cursor: pointer;
    color: #555;
    font-weight: 500;
    transition: all 0.15s ease;
    border-left: 3px solid transparent;
}

.settings-nav-item:hover {
    background: #f0f4ff;
    color: #333;
}

.settings-nav-item.active {
    background: #e8f0fe;
    color: #1a73e8;
    border-left-color: #1a73e8;
    font-weight: 600;
}

.settings-nav-icon {
    font-size: 1.15rem;
}

/* ── Content Area ── */

.settings-content {
    flex: 1;
    padding: 2rem;
    position: relative;
    overflow-y: auto;
}

.settings-loading {
    display: flex;
    justify-content: center;
    align-items: center;
    min-height: 300px;
}

.settings-section h2 {
    margin: 0 0 0.25rem;
    font-size: 1.5rem;
    font-weight: 600;
}

.section-description {
    color: #6c757d;
    margin-bottom: 1.5rem;
}

/* ── Form Helpers ── */

.form-group {
    margin-bottom: 1rem;
}

.form-group label {
    display: block;
    font-weight: 500;
    margin-bottom: 0.35rem;
    font-size: 0.9rem;
    color: #444;
}

.settings-actions {
    display: flex;
    gap: 0.75rem;
    margin-top: 1.5rem;
    padding-top: 1.5rem;
    border-top: 1px solid #eee;
}

/* ── Profile ── */

.profile-layout {
    display: flex;
    gap: 2rem;
}

.avatar-area {
    display: flex;
    flex-direction: column;
    align-items: center;
    gap: 0.75rem;
    min-width: 140px;
}

.avatar-preview {
    width: 100px;
    height: 100px;
    border-radius: 50%;
    background: #1a73e8;
    display: flex;
    align-items: center;
    justify-content: center;
    overflow: hidden;
    position: relative;
}

.avatar-preview img {
    width: 100%;
    height: 100%;
    object-fit: cover;
    position: absolute;
    top: 0;
    left: 0;
}

.avatar-fallback {
    color: #fff;
    font-size: 2rem;
    font-weight: 600;
}

.avatar-url-display {
    text-align: center;
}

.avatar-url-display label {
    font-weight: 500;
    font-size: 0.85rem;
    color: #444;
    margin-bottom: 0.15rem;
    display: block;
}

.profile-fields {
    flex: 1;
}

/* ── Toggle Switches ── */

.toggle-group {
    background: #fff;
    border: 1px solid #eee;
    border-radius: 8px;
    overflow: hidden;
}

.toggle-row {
    display: flex;
    align-items: center;
    justify-content: space-between;
    padding: 1rem 1.25rem;
    border-bottom: 1px solid #f0f0f0;
}

.toggle-row:last-child {
    border-bottom: none;
}

.toggle-switch {
    position: relative;
    display: inline-block;
    width: 48px;
    height: 26px;
    flex-shrink: 0;
}

.toggle-switch input {
    opacity: 0;
    width: 0;
    height: 0;
}

.toggle-slider {
    position: absolute;
    cursor: pointer;
    inset: 0;
    background-color: #ccc;
    border-radius: 26px;
    transition: 0.2s;
}

.toggle-slider::before {
    content: "";
    position: absolute;
    height: 20px;
    width: 20px;
    left: 3px;
    bottom: 3px;
    background-color: #fff;
    border-radius: 50%;
    transition: 0.2s;
}

.toggle-switch input:checked + .toggle-slider {
    background-color: #1a73e8;
}

.toggle-switch input:checked + .toggle-slider::before {
    transform: translateX(22px);
}

/* ── Muted Channels ── */

.muted-channels {
    margin-top: 1.5rem;
}

.muted-channels h5 {
    margin-bottom: 0.75rem;
}

.channel-list {
    display: flex;
    flex-wrap: wrap;
    gap: 0.5rem;
}

.channel-item {
    display: flex;
    align-items: center;
    gap: 0.4rem;
    padding: 0.4rem 0.75rem;
    background: #f8f9fa;
